query:
DELETE FROM billing_items
WHERE id NOT IN (
  SELECT min_id FROM (
    SELECT MIN(id) AS min_id
    FROM billing_items
    GROUP BY invoiceNumber, description, lineAmount, contactName
  ) AS keepers
);

